import java.awt.*;
public class ColorEquality {
    public static void main(String[] args) {
        Color a = Color.RED;
        Color b = new Color(255, 0, 0);
        System.out.println(a == b);
        System.out.println(a.equals(b));
        System.out.println(a.getRGB() == b.getRGB());
    }
